import sys
it = iter(sys.stdin.read().split())
n = int(next(it))
nums = [int(next(it)) for _ in range(n)]
target = int(next(it))

def search(nums, target):
    if target in nums:
        return nums.index(target)
    return -1

print(search(nums, target))

